def _init_gettext():
    """Initializes gettext translation function for this module."""
    try:
        translator = gettext.translation("ldicons", localedir=LOCALE_DIR, fallback=True)
        return translator.gettext
    except Exception:
        return lambda message: message


_ = _init_gettext()


class TeeStream:
    """
    Writes output simultaneously to the original stream and the log file.
    """

    def __init__(self, original_stream, file_handle):
        """
        Initializes tee stream targets.

        Parameters
        ----------

        original_stream : object
            Primary output stream (e.g. original stdout/stderr).

        file_handle : object
            File-like object used as secondary log target.
        """
        self.original_stream = original_stream
        self.file_handle = file_handle

    def write(self, data):
        """
        Writes data to both wrapped output destinations.

        Parameters
        ----------

        data : str
            Text chunk to forward to original stream and log file.
        """
        self.original_stream.write(data)
        self.file_handle.write(data)

    def flush(self):
        """
        Flushes both wrapped output destinations.
        """
        self.original_stream.flush()
        self.file_handle.flush()

    def isatty(self):
        """
        Returns whether the original stream behaves like a TTY.

        Returns
        -------

        bool:
            True if the original stream reports TTY behavior, else False.
        """
        return getattr(self.original_stream, "isatty", lambda: False)()


def setup_log_tee(log_path):
    """
    Enables output tee to console and log file.
    
    Parameters
    ----------
    
    log_path : str
        Target path of the log file.
    
    Returns
    -------
    
    object | None:
        Opened file handle or None.
    """
    if not log_path:
        return None

    expanded = os.path.expanduser(os.path.expandvars(log_path))
    log_dir = os.path.dirname(expanded)
    if log_dir:
        os.makedirs(log_dir, exist_ok=True)

    handle = open(expanded, "a", encoding="utf-8", buffering=1)
    sys.stdout = TeeStream(sys.stdout, handle)
    sys.stderr = TeeStream(sys.stderr, handle)
    print(f"Logging active: {expanded}")
    return handle


def parse_cli_args():
    """
    Parses command line arguments for ldicons.
    
    Returns
    -------
    
    argparse.Namespace:
        Parsed arguments.
    """
    parser = argparse.ArgumentParser(prog="ldicons", description="ldicons - Desktop-Icons for Wayland")
    parser.add_argument(
        "-c",
        "--conf",
        default=DEFAULT_CONFIG_PATH,
        help=f"Path to configuration file (default: {DEFAULT_CONFIG_PATH})",
    )
    parser.add_argument(
        "-l",
        "--log",
        default=DEFAULT_LOG_PATH,
        help=f"Path to log file (default: {DEFAULT_LOG_PATH})",
    )
    parser.add_argument(
        "-p",
        "--pos",
        default=DEFAULT_POSITIONS_PATH,
        help=f"Path to positions file (default: {DEFAULT_POSITIONS_PATH})",
    )
    parser.add_argument(
        "--verbose",
        action="store_true",
        help="Enable verbose debug output.",
    )
    parser.add_argument(
        "-v",
        "--version",
        action="version",
        version=f"ldicons {__version__}",
    )
    return parser.parse_args()

class Monitor:
    """
    Holds metadata and rendering surfaces for a single physical output.
    """
    def __init__(self, output_id, wl_output):
        self.output_id = output_id
        self.wl_output = wl_output
        self.name = f"Output-{output_id}"
        self.x, self.y = 0, 0
        self.width, self.height = 0, 0
        self.scale = 1
        self.surface = None
        self.layer_surface = None
        self.configured = False
        self.ready = False

